import React from "react";
import {
  BrowserRouter as Router,
  Routes,
  Route,
  useLocation,
} from "react-router-dom";

import Login from "./pages/Login";
import Register from "./pages/Register";
import VentasHistorial from "./pages/VentasHistorial";

import Productos from "./pages/Productos";
import Dashboard from "./pages/Dashboard";
import Categorias from "./pages/Categorias";
import Usuarios from "./pages/Usuarios";
import Clientes from "./pages/Clientes.page";
import VentasPage from "./pages/Ventas";
im

import Layout from "./components/Layout";

function AppContent() {
  const location = useLocation();

  // Ocultar sidebar en Login y Register
  const sinSidebar =
    location.pathname === "/" || location.pathname === "/register";

  return (
    <>
      {sinSidebar ? (
        // Si NO hay sidebar, se renderiza la página tal cual
        <Routes>
          <Route path="/" element={<Login />} />
          <Route path="/register" element={<Register />} />
        </Routes>
      ) : (
        // Si hay sidebar, envolver todo en Layout
        <Layout>
          <Routes>
            <Route path="/dashboard" element={<Dashboard />} />
            <Route path="/productos" element={<Productos />} />
            <Route path="/categorias" element={<Categorias />} />
            <Route path="/usuarios" element={<Usuarios />} />
            <Route path="/clientes" element={<Clientes />} />
            <Route path="/ventas" element={<VentasPage />} />

            {/* RUTA DEL SUBMENÚ "VER REGISTRO" */}
            <Route path="/ventas-historial" element={<VentasHistorial />} />
          </Routes>
        </Layout>
      )}
    </>
  );
}

export default function App() {
  return (
    <Router>
      <AppContent />
    </Router>
  );
}
